class NautilusPortal:
    def __init__(self) -> None:
        self.adapters = {          # реестр суб-агентов
            "info1":  Info1Adapter(),
            "pro2":   Pro2Adapter(),
            "meta":   MetaAdapter(),
            "data2":  Data2Adapter(),
            "data7":  Data7Adapter(),
            ...
        }

def query(self, concept: str) -> PortalResult:
        all_entries = []
        for adapter in self.adapters.values():
            all_entries.extend(adapter.fetch(concept))

